entry main(x: Text) {
    resp = perform http.get("https://httpbin.org/json")
    if resp.ok {
        lines = split(resp.body, "\n")
        for line in lines {
            if "author" in line {
                parts = split(line, "\"")
                if length(parts) >= 4 {
                    return parts[3]
                }
            }
        }
        return "author not found"
    }
    return "HTTP request failed"
}

entry main(x: Text) {
    resp = perform http.get("https://api.github.com/repos/anthropics/anthropic-sdk-python")
    if resp.ok {
        lines = split(resp.body, "\n")
        for line in lines {
            if starts_with(trim(line), "\"language\":") {
                parts = split(line, ":")
                if length(parts) >= 2 {
                    value_part = trim(get(parts, 1))
                    value_part = replace(value_part, ",", "")
                    value_part = replace(value_part, "\"", "")
                    return value_part
                }
            }
        }
        return "language field not found"
    }
    return "HTTP request failed"
}

import translate from "stdlib/language"

entry main(x: Text) {
    resp = perform http.get("https://httpbin.org/json")
    if resp.ok {
        body = resp.body
        title_start = split(body, "\"title\": \"")
        if length(title_start) > 1 {
            title_end = split(get(title_start, 1), "\"")
            title = get(title_end, 0)
            korean = translate(title, "Korean")
            return korean
        }
    }
    return "error"
}

