intent classify_sentiment(text: Text) -> Text {
    goal: classify as positive or negative
}

pure fn count_sentiments(reviews: [Text]) -> Text {
    pos = 0
    neg = 0
    for review in reviews {
        label = classify_sentiment(review)
        if label == "positive" { pos = pos + 1 }
        if label == "negative" { neg = neg + 1 }
    }
    return join(["positive=", to_text(pos), " negative=", to_text(neg)], "")
}

entry main(x: Text) {
    content = perform file.read("/tmp/heaal_e2_data/reviews.txt")
    if is_error(content) { return unwrap_error(content) }
    lines = split(unwrap(content), "\n")
    reviews = []
    for line in lines {
        trimmed = trim(line)
        if length(trimmed) > 0 {
            reviews = append(reviews, trimmed)
        }
    }
    return count_sentiments(reviews)
}

pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}

entry main(x: Text) {
    result = factorial(10)
    write_result = perform file.write("/tmp/heaal_e2_out/factorial.txt", to_text(result))
    return "done"
}

intent classify_sentiment(text: Text) -> Text {
    goal: positive_or_negative
}

pure fn is_positive(label: Text) -> Boolean {
    return label == "positive"
}

pure fn is_negative(label: Text) -> Boolean {
    return label == "negative"
}

entry main(x: Text) {
    content = perform file.read("/tmp/heaal_e2_data/reviews.txt")
    if is_error(content) {
        return unwrap_error(content)
    }

    reviews = split(unwrap(content), "\n")
    positives = []
    negatives = []

    for review in reviews {
        if length(trim(review)) > 0 {
            sentiment = classify_sentiment(review)
            if is_positive(sentiment) {
                positives = append(positives, review)
            }
            if is_negative(sentiment) {
                negatives = append(negatives, review)
            }
        }
    }

    pos_content = join(positives, "\n")
    neg_content = join(negatives, "\n")

    pos_result = perform file.write("/tmp/heaal_e2_out/positives.txt", pos_content)
    if is_error(pos_result) {
        return unwrap_error(pos_result)
    }

    neg_result = perform file.write("/tmp/heaal_e2_out/negatives.txt", neg_content)
    if is_error(neg_result) {
        return unwrap_error(neg_result)
    }

    return "done"
}

pure fn classify_severity(line: Text) -> Text {
    lower_line = lower(line)
    if starts_with(lower_line, "error") { return "ERROR" }
    if starts_with(lower_line, "warn") { return "WARN" }
    return "INFO"
}

pure fn count_by_severity(lines: [Text]) -> Text {
    info_count = 0
    warn_count = 0
    error_count = 0
    for line in lines {
        severity = classify_severity(line)
        if severity == "INFO" { info_count = info_count + 1 }
        if severity == "WARN" { warn_count = warn_count + 1 }
        if severity == "ERROR" { error_count = error_count + 1 }
    }
    return join(["INFO=", to_text(info_count), " WARN=", to_text(warn_count), " ERROR=", to_text(error_count)], "")
}

entry main(x: Text) {
    content = perform file.read("/tmp/heaal_e2_data/log.txt")
    if is_error(content) { return unwrap_error(content) }
    lines = split(unwrap(content), "\n")
    return count_by_severity(lines)
}

