pure fn extract_uuid(body: Text) -> Text {
    parts = split(body, "\"uuid\": \"")
    if length(parts) < 2 { return "" }
    uuid_part = get(parts, 1)
    end = split(uuid_part, "\"")
    return get(end, 0)
}

entry main(x: Text) {
    resp = perform http.get("https://httpbin.org/uuid")
    uuid = extract_uuid(resp.body)
    perform file.write("/tmp/heaal_e2_out/uuids.log", join([uuid, "\n"], ""))
    return uuid
}

